import "./styles/editor.css";
import { Suspense, use, useMemo } from "react";
import { useEditor, EditorContent, type JSONContent } from "@tiptap/react";
import type { Editor, Extensions } from "@tiptap/core";
import { BlockSideMenu } from "./menus/BlockSideMenu";
import { BubbleMenu } from "./menus/BubbleMenu";
import { SlashMenu } from "./menus/SlashMenu";
import { EmojiPicker } from "./menus/EmojiPicker";
import { TableControls } from "./menus/TableControls";
import {
  getEmojiArray,
  loadEmojiData,
} from "./menus/EmojiPicker/createEmojipicker/data";
import { defaultExtensions } from "./extensions";
import { editorStore } from "./store";
import {
  setEditorConfig,
  getEditorConfig,
  type SlashItem,
  type TurnIntoItem,
  type GetEmojiUrl,
  type PlaceholderConfig,
} from "./config";
import { defaultSlashItems } from "./menus/SlashMenu/slash-items";
import { defaultTurnIntoItems } from "./menus/TurnIntoMenu/items";
import { getEmojiUrl as twemojiGetEmojiUrl } from "./menus/EmojiPicker/getEmojiUrl";
import { cn } from "./lib/utils";
import type { TypedEditor } from "./types";

// ── Public types ──────────────────────────────────────────────────────

export interface OpenNotionOptions {
  /** Initial document content (JSON). Only applied on mount. */
  content?: JSONContent;

  /** Called whenever the document changes. */
  onChange?: (json: JSONContent) => void;

  /** Called once when the editor is ready. */
  onReady?: (editor: Editor) => void;

  /** Called when the selection changes. */
  onSelectionChange?: (editor: Editor) => void;

  /**
   * Enable localStorage persistence. Pass a string to use as the key prefix.
   * Leave undefined (default) for no persistence.
   */
  storageKey?: string;

  /** URL of the emoji data JSON. Defaults to "/emojis.json". */
  emojiDataUrl?: string;

  /** Override how emoji image URLs are generated. */
  getEmojiUrl?: GetEmojiUrl;

  /** Placeholder text (string or per-node function). */
  placeholder?: PlaceholderConfig;

  /** Whether the editor is editable. Default: true. */
  editable?: boolean;

  /** Whether to autofocus the editor on mount. Default: true. */
  autofocus?: boolean;

  /** Modify the slash menu items. */
  slashItems?: (defaults: SlashItem[]) => SlashItem[];

  /** Modify the "Turn into" menu items. */
  turnIntoItems?: (defaults: TurnIntoItem[]) => TurnIntoItem[];

  /** Modify the extension list. */
  extensions?: (defaults: Extensions) => Extensions;
}

export interface OpenNotionViewProps {
  /** Editor instance returned from useOpenNotion(). */
  editor: TypedEditor | null;

  /** Class applied to the container. */
  className?: string | undefined;
}

// ── Emoji data loader (Suspense boundary) ─────────────────────────────

const dataPromiseCache = new Map<string, Promise<void>>();

function useEmojiData(url: string) {
  let promise = dataPromiseCache.get(url);
  if (!promise) {
    promise = loadEmojiData(url).then(() => void 0);
    dataPromiseCache.set(url, promise);
  }
  use(promise);
}

// ── The hook: creates and manages the editor ─────────────────────────

export function useOpenNotion({
  content,
  onChange,
  onReady,
  onSelectionChange,
  storageKey,
  emojiDataUrl = "/emojis.json",
  getEmojiUrl,
  placeholder,
  editable = true,
  autofocus = true,
  slashItems,
  turnIntoItems,
  extensions,
}: OpenNotionOptions = {}): TypedEditor | null {
  // Wait for emoji data. Requires Suspense boundary from caller.
  useEmojiData(emojiDataUrl);

  // Set config once, before any menu renders.
  useMemo(() => {
    setEditorConfig({
      slashItems: slashItems
        ? slashItems(defaultSlashItems)
        : defaultSlashItems,
      turnIntoItems: turnIntoItems
        ? turnIntoItems(defaultTurnIntoItems)
        : defaultTurnIntoItems,
      extensionsFn: extensions,
      emojiDataUrl,
      getEmojiUrl: getEmojiUrl ?? twemojiGetEmojiUrl,
      storageKey: storageKey ?? false,
      placeholder,
    });
  }, [
    slashItems,
    turnIntoItems,
    extensions,
    emojiDataUrl,
    getEmojiUrl,
    storageKey,
    placeholder,
  ]);

  const emojis = getEmojiArray();

  const editor = useEditor({
    extensions: (() => {
      const defaults = defaultExtensions(emojis);
      return extensions ? extensions(defaults) : defaults;
    })(),
    content: content ?? "",
    editable,
    autofocus,
    immediatelyRender: false,

    ...(storageKey || onselectionchange
      ? {
          onSelectionUpdate: (props) => {
            const ed = props.editor;
            const key = getEditorConfig().storageKey;
            if (key) {
              const { from } = ed.state.selection;
              localStorage.setItem(`${key}-cursor`, String(from));
            }
            onSelectionChange?.(ed);
          },
        }
      : {}),

    ...(onChange || storageKey
      ? {
          onUpdate: (props) => {
            const ed = props.editor;
            const json = ed.getJSON();
            const key = getEditorConfig().storageKey;
            if (key) {
              localStorage.setItem(`${key}-content`, JSON.stringify(json));
            }
            onChange?.(json);
          },
        }
      : {}),

    ...(content || onReady || storageKey
      ? {
          onCreate: (props) => {
            const ed = props.editor;
            const key = getEditorConfig().storageKey;
            if (key && content === undefined) {
              const savedContent = localStorage.getItem(`${key}-content`);
              const savedCursor = localStorage.getItem(`${key}-cursor`);
              if (savedContent) {
                try {
                  ed.commands.setContent(JSON.parse(savedContent));
                  if (savedCursor) {
                    ed.commands.setTextSelection(Number(savedCursor));
                  }
                } catch {
                  // Ignore malformed saved content
                }
              }
            }
            if (autofocus) ed.commands.focus();
            onReady?.(ed);
          },
        }
      : {}),
  }) as TypedEditor | null;

  return editor;
}

// ── The view: renders the editor UI ──────────────────────────────────

export function OpenNotionView({
  editor,
  className = "pl-20 pr-10 py-16",
}: OpenNotionViewProps) {
  if (!editor) return null;

  return (
    <div
      ref={(el) => {
        editorStore.set({ editor, editorContainer: el });
      }}
      className={cn(
        "relative w-full cursor-text",
        "max-w-4xl min-h-svh cursor-text bg-background border border-border",
        className,
      )}
      onClick={() => editor.chain().focus().run()}
    >
      <BlockSideMenu />
      <BubbleMenu editor={editor} />
      <SlashMenu />
      <EmojiPicker />
      <TableControls />

      <EditorContent editor={editor as any} />
    </div>
  );
}

// ── Suspense wrapper (so consumers don't need to remember) ──────────

export interface OpenNotionProps extends OpenNotionOptions {
  /** Class applied to the container. */
  className?: string;

  /** Fallback shown while emoji data loads. */
  fallback?: React.ReactNode;
}

/**
 * Convenience wrapper for the common case: one editor, no parent-level
 * control, use defaults. For imperative control or custom layouts, use
 * `useOpenNotion()` + `<OpenNotionView>` directly.
 */
export function OpenNotion({
  className,
  fallback = (
    <div className="w-dvw h-dvh flex justify-center items-center text-4xl">
      Loading...
    </div>
  ),
  ...options
}: OpenNotionProps) {
  return (
    <Suspense fallback={fallback}>
      <OpenNotionInner options={options} className={className} />
    </Suspense>
  );
}

function OpenNotionInner({
  options,
  className,
}: {
  options: OpenNotionOptions;
  className?: string | undefined;
}) {
  const editor = useOpenNotion(options);
  return <OpenNotionView editor={editor} className={className} />;
}

export { OpenNotion, OpenNotionView, useOpenNotion } from "./Editor";

export type {
  OpenNotionProps,
  OpenNotionOptions,
  OpenNotionViewProps,
} from "./Editor";

export type {
  SlashItem,
  TurnIntoItem,
  GetEmojiUrl,
  PlaceholderConfig,
} from "./config";

export { defaultSlashItems } from "./menus/SlashMenu/slash-items";
export { defaultTurnIntoItems } from "./menus/TurnIntoMenu/items";

export type { TypedEditor } from "./types";

// editor-store.ts
import { useSyncExternalStore } from "react";
import type { TypedEditor } from "./types";

export interface NodeBlock {
  element: HTMLElement;
  pos: number;
  nodeType: string;
}

interface EditorStoreState {
  editor: TypedEditor | null;
  editorContainer: HTMLElement | null;
  hoveredBlock: NodeBlock | null;
}

function createEditorStore() {
  let state: EditorStoreState = {
    editor: null,
    hoveredBlock: null,
    editorContainer: null,
  };
  const listeners = new Set<() => void>();
  const notify = () => listeners.forEach((l) => l());

  return {
    subscribe: (l: () => void) => {
      listeners.add(l);
      return () => listeners.delete(l);
    },
    set(partial: Partial<EditorStoreState>) {
      const entries = Object.entries(partial) as [
        keyof EditorStoreState,
        unknown,
      ][];
      const changed = entries.some(([k, v]) => state[k] !== v);
      if (!changed) return;
      state = { ...state, ...partial };
      notify();
    },
    get: () => state,
  };
}

export const editorStore = createEditorStore();

export function useEditorStore<T>(selector: (s: EditorStoreState) => T): T {
  return useSyncExternalStore(editorStore.subscribe, () =>
    selector(editorStore.get()),
  );
}

export const useEditor = () => useEditorStore((s) => s.editor);

import type { Editor } from "@tiptap/react";

// ── Registry (source of truth) ────────────────────────────────────────

export const NODE_NAMES = [
  "doc",
  "text",
  "paragraph",
  "heading",
  "bulletList",
  "orderedList",
  "taskList",
  "listItem",
  "taskItem",
  "blockquote",
  "codeBlock",
  "horizontalRule",
  "hardBreak",
  "image",
  "emoji",
  "table",
  "tableRow",
  "tableCell",
  "tableHeader",
  "callout",
] as const;

export const MARK_NAMES = [
  "bold",
  "italic",
  "strike",
  "code",
  "link",
  "textStyle",
  "underline",
] as const;

export type NodeName = (typeof NODE_NAMES)[number];
export type MarkName = (typeof MARK_NAMES)[number];
export type EntityName = NodeName | MarkName;

// ── Attribute shapes ──────────────────────────────────────────────────

type Empty = Record<string, never>;

// Cross-cutting attrs applied via BlockStyles + TextAlign
interface BlockAttrs {
  backgroundColor?: string;
  textColor?: string;
  fontSize?: string;
  fontFamily?: string;
  textAlign?: "left" | "center" | "right" | "justify";
}

interface CellAttrs {
  backgroundColor?: string;
  colspan?: number;
  rowspan?: number;
  colwidth?: number[] | null;
}

export interface NodeAttrs {
  doc: Empty;
  text: Empty;
  hardBreak: Empty;
  horizontalRule: Empty;
  paragraph: BlockAttrs;
  heading: BlockAttrs & { level: 1 | 2 | 3 };
  blockquote: BlockAttrs;
  bulletList: Empty;
  orderedList: { start?: number };
  taskList: Empty;
  listItem: Empty;
  taskItem: { checked?: boolean };
  codeBlock: { language?: string };
  image: {
    src?: string;
    caption?: string;
    align?: "left" | "center" | "full";
    width?: string | number;
  };
  emoji: { name?: string };
  table: Empty;
  tableRow: Empty;
  tableCell: CellAttrs;
  tableHeader: CellAttrs;
}

export interface MarkAttrs {
  bold: Empty;
  italic: Empty;
  strike: Empty;
  code: Empty;
  underline: Empty;
  link: { href: string; target?: string };
  textStyle: { color?: string; fontFamily?: string; fontSize?: string };
}

type AttrsFor<T extends EntityName> = T extends keyof NodeAttrs
  ? NodeAttrs[T]
  : T extends keyof MarkAttrs
    ? MarkAttrs[T]
    : never;

// ── Typed editor ──────────────────────────────────────────────────────

export type TypedEditor = Omit<Editor, "isActive" | "getAttributes"> & {
  isActive<T extends EntityName>(
    name: T,
    attrs?: Partial<AttrsFor<T>>,
  ): boolean;
  isActive(attrs: Partial<BlockAttrs>): boolean;
  getAttributes<T extends EntityName>(name: T): AttrsFor<T>;
};

import type { Extensions, Range, ChainedCommands } from "@tiptap/core";
import type { Node as PMNode, Schema } from "@tiptap/pm/model";
import type { LucideIcon } from "lucide-react";
import type { JSONContent } from "@tiptap/react";
import type { TypedEditor } from "./types";
import { getEmojiUrl as defaultGetEmojiUrl } from "./menus/EmojiPicker/getEmojiUrl";

// ── Public item shapes ────────────────────────────────────────────────

export interface SlashItem {
  id: string;
  title: string;
  description?: string;
  icon: LucideIcon;
  group: string;
  action: (editor: TypedEditor, range: Range) => void;
}

export interface TurnIntoItem {
  id: string;
  label: string;
  icon: LucideIcon;
  isActive: (editor: TypedEditor) => boolean;
  applyChain: (chain: ChainedCommands) => ChainedCommands;
  buildNode: (schema: Schema) => PMNode;
}

/**
 * Returns a URL for an emoji image.
 *
 * The `source` argument describes *where* the emoji is being rendered, so
 * consumers can vary providers, sizes, or formats per context if they want to.
 *
 * - `"inline"`       — inline within editor text (small, performance-sensitive)
 * - `"picker-grid"`  — main emoji grid inside the picker popover (medium)
 * - `"category-bar"` — category tab icons at the bottom of the picker (small, often animated)
 * - `"callout-icon"` — callout block's leading icon (medium)
 *
 * Consumers can ignore the `source` argument entirely and return a single URL
 * for all cases — it's metadata, not a required branching signal.
 *
 * Avoid breaking changes for source` in the future.
 */
export type GetEmojiUrl = (
  hexId: string,
  source: "inline" | "picker-grid" | "category-bar" | "callout-icon",
) => string;

// ── Placeholder type ──────────────────────────────────────────────────

export type PlaceholderConfig = string | ((node: PMNode) => string);

// ── Full resolved config ──────────────────────────────────────────────

export interface EditorConfig {
  slashItems: SlashItem[];
  turnIntoItems: TurnIntoItem[];
  extensionsFn?: ((defaults: Extensions) => Extensions) | undefined;
  emojiDataUrl: string;
  getEmojiUrl: GetEmojiUrl;
  storageKey: string | false;
  placeholder?: PlaceholderConfig | undefined;
  initialContent?: JSONContent | undefined;
  onChange?: ((json: JSONContent) => void) | undefined;
}

// ── Module-level singleton ────────────────────────────────────────────

// NOTE: defaults are set lazily via setEditorConfig on <Editor> mount.
// These are placeholder values — never read before the editor mounts.
let config: EditorConfig = {
  slashItems: [],
  turnIntoItems: [],
  emojiDataUrl: "/emoji.json",
  getEmojiUrl: defaultGetEmojiUrl,
  storageKey: false,
};

export const setEditorConfig = (next: Partial<EditorConfig>): void => {
  config = { ...config, ...next };
};

export const getEditorConfig = (): EditorConfig => config;

import { clsx, type ClassValue } from "clsx"
import { twMerge } from "tailwind-merge"

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs))
}

