import { Extension } from "@tiptap/core";
import type { Node as PMNode } from "@tiptap/pm/model";
import type { NodeName } from "../types";

declare module "@tiptap/core" {
  interface Commands<ReturnType> {
    blockStyles: {
      toggleBlockBackground: (color: string, pos?: number) => ReturnType;
      toggleBlockTextColor: (color: string, pos?: number) => ReturnType;
      toggleBlockFontSize: (size: string, pos?: number) => ReturnType;
      toggleBlockFontFamily: (family: string, pos?: number) => ReturnType;
    };
  }
}

export const BlockStyles = Extension.create<{ types: string[] }>({
  name: "blockStyles",

  addOptions() {
    return {
      types: [
        "paragraph",
        "heading",
        "blockquote",
        "callout",
      ] satisfies NodeName[],
    };
  },

  addGlobalAttributes() {
    return [
      {
        types: this.options.types,
        attributes: {
          backgroundColor: {
            default: null,
            parseHTML: (el) =>
              (el as HTMLElement).style.backgroundColor || null,
            renderHTML: (attrs) =>
              attrs.backgroundColor
                ? { style: `background-color: ${attrs.backgroundColor}` }
                : {},
          },
          textColor: {
            default: null,
            parseHTML: (el) => (el as HTMLElement).style.color || null,
            renderHTML: (attrs) =>
              attrs.textColor ? { style: `color: ${attrs.textColor}` } : {},
          },
          fontSize: {
            default: null,
            parseHTML: (el) => (el as HTMLElement).style.fontSize || null,
            renderHTML: (attrs) =>
              attrs.fontSize ? { style: `font-size: ${attrs.fontSize}` } : {},
          },
          fontFamily: {
            default: null,
            parseHTML: (el) => (el as HTMLElement).style.fontFamily || null,
            renderHTML: (attrs) =>
              attrs.fontFamily
                ? { style: `font-family: ${attrs.fontFamily}` }
                : {},
          },
        },
      },
    ];
  },

  addCommands() {
    const types = this.options.types;

    /** Resolves target block; falls back to the current selection's parent block. */
    const resolveTargetBlock = (
      state: { selection: any; doc: any },
      pos?: number,
    ): { pos: number; node: PMNode } | null => {
      const targetPos = pos ?? state.selection.$from.before(1);
      const node = state.doc.nodeAt(targetPos);
      if (!node || !types.includes(node.type.name)) return null;
      return { pos: targetPos, node };
    };

    const toggleBlockAttr =
      (attrKey: string) =>
      (value: string, pos?: number) =>
      ({ tr, dispatch, state }: any) => {
        const target = resolveTargetBlock(state, pos);
        if (!target) return false;
        const current = target.node.attrs[attrKey];

        if (!current && !value) return false;

        const next = current === value ? null : value;
        if (dispatch) {
          tr.setNodeMarkup(target.pos, undefined, {
            ...target.node.attrs,
            [attrKey]: next,
          });
        }
        return true;
      };

    return {
      toggleBlockBackground: toggleBlockAttr("backgroundColor"),
      toggleBlockTextColor: toggleBlockAttr("textColor"),
      toggleBlockFontSize: toggleBlockAttr("fontSize"),
      toggleBlockFontFamily: toggleBlockAttr("fontFamily"),
    };
  },

  addKeyboardShortcuts() {
    return {
      Enter: ({ editor }) => {
        const { $from } = editor.state.selection;
        const node = $from.node();

        if (!this.options.types.includes(node.type.name)) return false;

        return editor
          .chain()
          .splitBlock({ keepMarks: false })
          .updateAttributes(node.type, {
            backgroundColor: null,
            textColor: null,
            fontSize: null,
            fontFamily: null,
          })
          .run();
      },
    };
  },
});

// extensions/callout/callout.ts
import { Node, mergeAttributes } from "@tiptap/core";
import { ReactNodeViewRenderer } from "@tiptap/react";
import { CalloutView } from "../blocks/Callout";

declare module "@tiptap/core" {
  interface Commands<ReturnType> {
    callout: {
      setCallout: (attrs?: { emoji?: string }) => ReturnType;
      toggleCallout: () => ReturnType;
    };
  }
}

export const Callout = Node.create({
  name: "callout",
  group: "block",
  content: "block+",
  defining: true,

  addAttributes() {
    return {
      emoji: { default: "💡" },
    };
  },

  parseHTML() {
    return [{ tag: "div[data-callout]" }];
  },

  renderHTML({ node, HTMLAttributes }) {
    return [
      "div",
      mergeAttributes(HTMLAttributes, {
        "data-callout": "",
        "data-emoji": node.attrs.emoji,
      }),
      ["span", { "data-callout-emoji": "" }, node.attrs.emoji],
      ["div", { "data-callout-content": "" }, 0],
    ];
  },

  addCommands() {
    return {
      setCallout:
        (attrs) =>
        ({ commands }) =>
          commands.insertContent({
            type: this.name,
            attrs,
            content: [{ type: "paragraph" }],
          }),
      toggleCallout:
        () =>
        ({ commands, editor }) => {
          if (editor.isActive("callout")) {
            return commands.lift("callout");
          }
          return commands.setCallout();
        },
    };
  },

  addKeyboardShortcuts() {
    return {
      // Exit callout on Enter at end of empty block
      Enter: ({ editor }) => {
        if (!editor.isActive("callout")) return false;
        const { $from } = editor.state.selection;

        // Find the callout node depth
        let depth = $from.depth;
        while (depth > 0 && $from.node(depth).type.name !== "callout") depth--;
        if (depth === 0) return false;

        const calloutNode = $from.node(depth);
        const insideBlock = $from.node(depth + 1);

        // Only exit if: cursor is in the last child, that child is an empty paragraph
        const isLastChild = $from.index(depth) === calloutNode.childCount - 1;
        const isEmpty =
          insideBlock.type.name === "paragraph" &&
          insideBlock.content.size === 0;

        if (isLastChild && isEmpty) {
          return editor.commands.lift("callout");
        }
        return false;
      },
    };
  },

  addNodeView() {
    return ReactNodeViewRenderer(CalloutView);
  },
});

import CodeBlock from "@tiptap/extension-code-block";
import { ReactNodeViewRenderer } from "@tiptap/react";
import { Plugin, PluginKey } from "@tiptap/pm/state";
import { Decoration, DecorationSet } from "@tiptap/pm/view";
import type { Node as ProseMirrorNode } from "@tiptap/pm/model";
import { CodeBlockView } from "../blocks/CodeBlock";
import { preloadLangs } from "../blocks/CodeBlock/languages";

import { createHighlighterCore } from "@shikijs/core";
import { createJavaScriptRegexEngine } from "@shikijs/engine-javascript";
import lightPlus from "@shikijs/themes/light-plus";
import darkPlus from "@shikijs/themes/dark-plus";

const langLoaders: Record<string, () => Promise<any>> = {
  javascript: () => import("@shikijs/langs/javascript"),
  typescript: () => import("@shikijs/langs/typescript"),
  python: () => import("@shikijs/langs/python"),
  json: () => import("@shikijs/langs/json"),
  html: () => import("@shikijs/langs/html"),
  css: () => import("@shikijs/langs/css"),
  bash: () => import("@shikijs/langs/bash"),
  rust: () => import("@shikijs/langs/rust"),
};

const darkTheme = darkPlus.name!;
const lightTheme = lightPlus.name!;

// ── Types (duck-typed to avoid shiki internal type deps) ──────────────

interface ShikiHighlighter {
  codeToTokens: (
    code: string,
    options: { lang: string; theme: string },
  ) => { tokens: { content: string; color?: string }[][] };
  getLoadedLanguages: () => string[];
  loadLanguage: (...langs: string[]) => Promise<void>;
}

// ── Decoration builder ────────────────────────────────────────────────

export const shikiPluginKey = new PluginKey("shikiHighlight");

function buildDecorations(
  doc: ProseMirrorNode,
  highlighter: ShikiHighlighter | null,
  typeName: string,
): DecorationSet {
  if (!highlighter) return DecorationSet.empty;

  const isDark = document.documentElement.classList.contains("dark");
  const theme = isDark ? darkTheme : lightTheme;

  const loaded = highlighter.getLoadedLanguages();
  const decorations: Decoration[] = [];

  doc.descendants((node, pos) => {
    if (node.type.name !== typeName) return;

    const lang = node.attrs.language || "plaintext";
    const code = node.textContent;
    if (!code.length || lang === "plaintext" || !loaded.includes(lang)) return;

    try {
      const { tokens } = highlighter.codeToTokens(code, { lang, theme });
      let offset = pos + 1;

      for (let i = 0; i < tokens.length; i++) {
        for (const token of tokens[i]) {
          const from = offset;
          const to = from + token.content.length;
          if (token.color) {
            decorations.push(
              Decoration.inline(from, to, { style: `color: ${token.color}` }),
            );
          }
          offset = to;
        }
        if (i < tokens.length - 1) offset += 1;
      }
    } catch {
      /* language parse error — render plain */
    }
  });

  return DecorationSet.create(doc, decorations);
}

