import {
  combineTransactionSteps,
  findChildrenInRange,
  getChangedRanges,
  InputRule,
  mergeAttributes,
  Node,
  PasteRule,
} from "@tiptap/core";
import type { Transaction } from "@tiptap/pm/state";
import { Plugin, PluginKey, TextSelection } from "@tiptap/pm/state";
import emojiRegex from "emoji-regex";

import { type Emoji } from "../menus/EmojiPicker/createEmojipicker/data";
import { emojiToShortcode } from "./helpers/emojiToShortcode";
import { shortcodeToEmoji } from "./helpers/shortcodeToEmoji";
import { getEditorConfig } from "../config";

declare module "@tiptap/core" {
  interface Commands<ReturnType> {
    emoji: {
      /**
       * Add an emoji
       */
      setEmoji: (shortcode: string) => ReturnType;
    };
  }
}

export type EmojiOptions = {
  HTMLAttributes: Record<string, any>;
  emojis: Emoji[];
};

export const inputRegex = /:([a-zA-Z0-9_+-]+):$/;

export const pasteRegex = /(^|\s):([a-zA-Z0-9_+-]+):/g;

export const EmojiNode = Node.create<EmojiOptions>({
  name: "emoji",

  inline: true,

  group: "inline",

  atom: true,

  selectable: false,

  addKeyboardShortcuts() {
    const step = (dir: -1 | 1) => () => {
      const { state, view } = this.editor;
      const { $from, empty } = state.selection;
      if (!empty) return false;

      const target = $from.pos + dir;
      if (target < 0 || target > state.doc.content.size) return false;

      const nodeBefore = $from.nodeBefore;
      const nodeAfter = $from.nodeAfter;
      const adjacent = dir === -1 ? nodeBefore : nodeAfter;

      if (!adjacent || adjacent.type.name !== this.name) return false;

      const $target = state.doc.resolve(target);
      view.dispatch(state.tr.setSelection(TextSelection.near($target, dir)));
      return true;
    };

    return { ArrowLeft: step(-1), ArrowRight: step(1) };
  },

  addOptions() {
    return {
      HTMLAttributes: {},
      emojis: [],
    };
  },

  addAttributes() {
    return {
      name: {
        default: null,
        parseHTML: (element) => element.dataset.name,
        renderHTML: (attributes) => ({
          "data-name": attributes.name,
        }),
      },
    };
  },

  parseHTML() {
    return [
      {
        tag: `span[data-type="${this.name}"]`,
      },
    ];
  },

  renderHTML({ HTMLAttributes, node }) {
    const emojiItem = shortcodeToEmoji(node.attrs.name, this.options.emojis);
    const attributes = mergeAttributes(
      HTMLAttributes,
      this.options.HTMLAttributes,
      { "data-type": this.name },
    );

    if (!emojiItem) {
      return ["span", attributes, `:${node.attrs.name}:`];
    }

    return [
      "span",
      attributes,
      [
        "img",
        {
          src: getEditorConfig().getEmojiUrl(emojiItem.id, "inline"),
          draggable: "false",
          loading: "lazy",
          alt: `${emojiItem.name} emoji`,
          style:
            "width: 1.2em; height: 1.2em; display: inline; margin-inline: 0.15em; margin-top: -0.1em;",
        },
      ],
    ];
  },

  renderText({ node }) {
    const emojiItem = shortcodeToEmoji(node.attrs.name, this.options.emojis);

    return emojiItem?.unicode || `:${node.attrs.name}:`;
  },

  renderMarkdown: (node) => {
    if (!node.attrs?.name) {
      return "";
    }

    return `:${node.attrs.name}:`;
  },

  addCommands() {
    return {
      setEmoji:
        (shortcode) =>
        ({ chain }) => {
          const emojiItem = shortcodeToEmoji(shortcode, this.options.emojis);

          if (!emojiItem) {
            return false;
          }

          chain()
            .insertContent({
              type: this.name,
              attrs: {
                name: emojiItem.name,
              },
            })
            .command(({ tr, state }) => {
              tr.setStoredMarks(
                state.doc.resolve(state.selection.to - 1).marks(),
              );
              return true;
            })
            .run();

          return true;
        },
    };
  },

  addInputRules() {
    const inputRules: InputRule[] = [];

    inputRules.push(
      new InputRule({
        find: inputRegex,
        handler: ({ range, match, chain }) => {
          const name = match[1];

          if (!shortcodeToEmoji(name, this.options.emojis)) {
            return;
          }

          chain()
            .insertContentAt(range, {
              type: this.name,
              attrs: {
                name,
              },
            })
            .command(({ tr, state }) => {
              tr.setStoredMarks(
                state.doc.resolve(state.selection.to - 1).marks(),
              );
              return true;
            })
            .run();
        },
      }),
    );

    return inputRules;
  },

  addPasteRules() {
    return [
      new PasteRule({
        find: pasteRegex,
        handler: ({ range, match, chain }) => {
          const prefix = match[1] || "";
          const name = match[2];

          if (!shortcodeToEmoji(name, this.options.emojis)) {
            return;
          }

          const shortcodeFrom = range.from + prefix.length;
          const shortcodeTo = range.to;

          chain()
            .insertContentAt(
              { from: shortcodeFrom, to: shortcodeTo },
              {
                type: this.name,
                attrs: {
                  name,
                },
              },
              {
                updateSelection: false,
              },
            )
            .command(({ tr, state }) => {
              tr.setStoredMarks(
                state.doc.resolve(state.selection.to - 1).marks(),
              );
              return true;
            })
            .run();
        },
      }),
    ];
  },

  addProseMirrorPlugins() {
    return [
      new Plugin({
        key: new PluginKey("emoji"),
        props: {
          handleDoubleClickOn: (_view, pos, node) => {
            if (node.type !== this.type) {
              return false;
            }

            const from = pos;
            const to = from + node.nodeSize;

            this.editor.commands.setTextSelection({
              from,
              to,
            });

            return true;
          },
        },

        appendTransaction: (transactions, oldState, newState) => {
          if (this.editor.view.composing) {
            return;
          }
          const docChanges =
            transactions.some((transaction) => transaction.docChanged) &&
            !oldState.doc.eq(newState.doc);

          if (!docChanges) {
            return;
          }

          const { tr } = newState;
          const transform = combineTransactionSteps(
            oldState.doc,
            transactions as Transaction[],
          );
          const changes = getChangedRanges(transform);

          changes.forEach(({ newRange }) => {
            if (newState.doc.resolve(newRange.from).parent.type.spec.code) {
              return;
            }

            const textNodes = findChildrenInRange(
              newState.doc,
              newRange,
              (node) => node.type.isText,
            );

            textNodes.forEach(({ node, pos }) => {
              if (!node.text) {
                return;
              }

              const matches = [...node.text.matchAll(emojiRegex())];

              matches.forEach((match) => {
                if (match.index === undefined) {
                  return;
                }

                const emoji = match[0];
                const name = emojiToShortcode(emoji, this.options.emojis);

                if (!name) {
                  return;
                }

                const from = tr.mapping.map(pos + match.index);

                if (newState.doc.resolve(from).parent.type.spec.code) {
                  return;
                }

                const to = from + emoji.length;
                const emojiNode = this.type.create({
                  name,
                });

                tr.replaceRangeWith(from, to, emojiNode);

                tr.setStoredMarks(newState.doc.resolve(from).marks());
              });
            });
          });

          if (!tr.steps.length) {
            return;
          }

          return tr;
        },
      }),
    ];
  },
});

import type { Emoji } from "../../menus/EmojiPicker/createEmojipicker/data";
import { removeVariationSelector } from "./removeVariationSelector";

export function emojiToShortcode(
  emoji: string,
  emojis: Emoji[],
): string | undefined {
  return emojis.find((item) => item.unicode === removeVariationSelector(emoji))
    ?.shortcodes[0];
}

/**
 * Removes duplicated values within an array.
 * Supports numbers, strings and objects.
 */
export function removeDuplicates<T>(array: T[], by = JSON.stringify): T[] {
  const seen: Record<any, any> = {}

  return array.filter(item => {
    const key = by(item)

    return Object.prototype.hasOwnProperty.call(seen, key) ? false : (seen[key] = true)
  })
}

export function removeVariationSelector(value: string): string {
  return value.replace('\u{FE0E}', '').replace('\u{FE0F}', '')
}

import type { Emoji } from "../../menus/EmojiPicker/createEmojipicker/data";

export function shortcodeToEmoji(
  shortcode: string,
  emojis: Emoji[],
): Emoji | undefined {
  return emojis.find(
    (item) => shortcode === item.name || item.shortcodes.includes(shortcode),
  );
}

