type Dropdownprops = Omit<Parameters<typeof DropdownMenu>[0], "children">;
interface BlockContextMenuProps extends Dropdownprops {
  trigger: Parameters<typeof DropdownMenuTrigger>[0]["render"];
}
export const BlockContextMenu = memo(
  ({ trigger, ...props }: BlockContextMenuProps) => {
    const handleSelect = useCallback(
      (id: string) => {
        const { editor, hoveredBlock } = editorStore.get();
        if (!editor || !hoveredBlock) return;

        const { pos } = hoveredBlock;
        const node = editor.state.doc.nodeAt(pos);

        switch (id) {
          case "delete":
            if (node) {
              editor
                .chain()
                .focus()
                .deleteRange({ from: pos, to: pos + node.nodeSize })
                .run();
            }
            break;
          case "duplicate":
            if (node) {
              editor
                .chain()
                .focus()
                .insertContentAt(pos + node.nodeSize, node.toJSON())
                .run();
            }
            break;
          case "copy-link": {
            const url = `${window.location.href}#block-${pos}`;
            navigator.clipboard.writeText(url).catch(() => {
              console.warn("Failed to copy link to clipboard");
            });
            break;
          }
        }

        close();
      },
      [close],
    );

    const blockpos = useEditorStore((s) => s.hoveredBlock?.pos);

    const renderItems = (items: MenuItem[]) =>
      items.map(({ id, label, icon: Icon, shortcut }) => (
        <DropdownMenuItem
          key={id}
          className="flex items-center gap-2 h-8 px-2 py-1 rounded-md"
          onClick={() => handleSelect(id)}
        >
          <Icon className="size-4" />
          <span>{label}</span>
          {shortcut && (
            <DropdownMenuShortcut className="ml-auto">
              {shortcut}
            </DropdownMenuShortcut>
          )}
        </DropdownMenuItem>
      ));

    return (
      <DropdownMenu {...props}>
        <DropdownMenuTrigger render={trigger} />
        <DropdownMenuContent
          side="right"
          align="start"
          sideOffset={8}
          className="w-[260px] max-h-[400px] overflow-y-auto ease-in duration-200"
        >
          {renderItems(topItems)}

          <DropdownMenuSeparator className="h-px my-1" />

          <TurnIntomenu blockPos={blockpos!} isSubMenu>
            <Type className="size-4" />
            <span>Turn into</span>
          </TurnIntomenu>

          <BlockColorMenu blockPos={blockpos} isSubMenu>
            <Palette className="size-4" />
            <span>Color</span>
          </BlockColorMenu>

          <FontSizeMenu blockPos={blockpos} isSubMenu>
            <ALargeSmall className="size-4" />
            <span>Font size</span>
          </FontSizeMenu>

          <FontFamilyMenu blockPos={blockpos} isSubMenu>
            <CaseSensitive className="size-4" />
            <span>Font family</span>
          </FontFamilyMenu>

          <DropdownMenuSeparator className="h-px my-1" />

          {placeholderSubmenus.map(({ id, label, icon: Icon }) => (
            <DropdownMenuSub key={id}>
              <DropdownMenuSubTrigger className="flex items-center gap-2 h-8 px-2 py-1 rounded-md">
                <Icon className="size-4" />
                <span>{label}</span>
              </DropdownMenuSubTrigger>
              <DropdownMenuSubContent className="min-w-[180px] p-1 rounded-[10px]">
                <DropdownMenuItem
                  disabled
                  className="flex items-center gap-2 h-8 px-2 py-1 rounded-md"
                >
                  <span>Coming soon...</span>
                </DropdownMenuItem>
              </DropdownMenuSubContent>
            </DropdownMenuSub>
          ))}

          <DropdownMenuSeparator className="h-px my-1" />

          {renderItems(bottomItems)}
        </DropdownMenuContent>
      </DropdownMenu>
    );
  },
  (p, n) =>
    p.open === n.open &&
    p.trigger === n.trigger &&
    p.onOpenChange === n.onOpenChange,
);

import { useRef, useState, useCallback } from "react";
import { GripVertical, Plus } from "lucide-react";
import { useHoveredBlock } from "./useHoveredBlock";
import { BlockContextMenu } from "./BlockContextMenu";
import { cn } from "@/components/editor/lib/utils";
import { Button } from "@/components/editor/ui/button";
import "../styles/block-side-menu.css";
import { editorStore } from "../store";

export function BlockSideMenu() {
  const menuRef = useRef<HTMLDivElement>(null);
  const [open, setOpen] = useState(false);

  const { clearActive } = useHoveredBlock({ menuRef, open });

  const handlePlusClick = useCallback(() => {
    const { editor, hoveredBlock } = editorStore.get();
    if (!editor || !hoveredBlock) return;

    const pos = hoveredBlock.pos;
    const $pos = editor.state.doc.resolve(pos);
    if (!$pos.nodeAfter) return;
    const endOfBlock = $pos.pos + $pos.nodeAfter.nodeSize;
    editor
      .chain()
      .focus()
      .insertContentAt(endOfBlock, { type: "paragraph" })
      .setTextSelection(endOfBlock + 1)
      .insertContent("/")
      .run();
  }, []);

  const handleDragStart = useCallback(
    (e: React.DragEvent<HTMLButtonElement>) => {
      const { editor, hoveredBlock } = editorStore.get();
      if (!editor || !hoveredBlock) return;

      const { pos, element } = hoveredBlock;

      editor.commands.setNodeSelection(pos);
      editor.view.dragging = {
        slice: editor.view.state.selection.content(),
        move: true,
      };
      const rect = element.getBoundingClientRect();
      e.dataTransfer.setDragImage(
        element,
        e.clientX - rect.left,
        e.clientY - rect.top,
      );
    },
    [],
  );

  return (
    <div
      ref={menuRef}
      data-visible="false"
      className={cn(
        "absolute top-0 flex items-center left-2",
        "opacity-0 pointer-events-none",
        "data-[visible=true]:opacity-100 data-[visible=true]:pointer-events-auto",
        "after:absolute after:top-0 after:-right-full after:h-full after:w-full after:content-['']",
        "transition-[top,opacity] duration-200 ease-out will-change-[top]",
      )}
    >
      <Button
        variant="ghost"
        size="icon"
        onClick={handlePlusClick}
        aria-label="Add block"
      >
        <Plus className="size-4" />
      </Button>

      <div className="relative">
        <BlockContextMenu
          open={open}
          onOpenChange={(o, e) => {
            if (
              e.reason === "trigger-hover" ||
              e.reason === "focus-out" ||
              e.reason === "trigger-press"
            )
              return;

            if (!o) {
              setOpen(o);
              clearActive();
            }
          }}
          trigger={
            <Button
              variant="ghost"
              size="icon-sm"
              aria-label="Block options"
              className="cursor-grab"
              draggable
              onClick={() => {
                const { editor, hoveredBlock } = editorStore.get();
                if (!editor || !hoveredBlock) return;

                setOpen((p) => !p);
                editor.chain().focus().setNodeSelection(hoveredBlock.pos).run();
              }}
              onDragStart={handleDragStart}
              onDragEnd={() => {
                const { editor } = editorStore.get();
                if (!editor) return;

                editor.view.dragging = null;
              }}
            >
              <GripVertical className="size-4" />
            </Button>
          }
        />
      </div>
    </div>
  );
}

