import { memo, useCallback, useEffect, useMemo, useRef, useState } from "react";
import {
  Popover,
  PopoverContent,
  PopoverTitle,
} from "@/components/editor/ui/popover";
import Suggestion from "@tiptap/suggestion";
import { PluginKey } from "@tiptap/pm/state";
import { EmojiNode } from "../../extensions/Emoji";
import { PopoverArrow } from "@/components/editor/ui/PopoverArrow";
import { createEmojiPicker, type EmojiPickerApi } from "./createEmojipicker";
import { editorStore } from "../../store";

const EmojiSuggestionPluginKey = new PluginKey("emojiSuggestion");

export const EmojiPicker = memo(() => {
  const [anchor, setAnchor] = useState<DOMRect | null>(null);
  const [open, setOpen] = useState(false);

  const apiRef = useRef<EmojiPickerApi | null>(null);
  const rangeRef = useRef<{ from: number; to: number } | null>(null);

  const insertEmoji = useCallback((shortcode: string) => {
    if (!rangeRef.current) return;
    editorStore
      .get()
      .editor?.chain()
      .focus()
      .deleteRange(rangeRef.current)
      .setEmoji(shortcode)
      .run();
  }, []);

  const setContainer = useCallback(
    (node: HTMLDivElement | null) => {
      if (node) {
        apiRef.current = createEmojiPicker(node, { onSelect: insertEmoji });
        apiRef.current.renderAll();
      } else {
        apiRef.current?.destroy();
        apiRef.current = null;
      }
    },
    [insertEmoji],
  );

  useEffect(() => {
    const { editor } = editorStore.get();
    if (!editor) return;

    const plugin = Suggestion({
      editor: editor as any,
      char: ":",
      pluginKey: EmojiSuggestionPluginKey,
      render: () => ({
        onStart(props) {
          setAnchor(props.clientRect?.() ?? null);
          setOpen(true);
          rangeRef.current = props.range;
          if (props.query) apiRef.current?.renderFiltered(props.query);
          else apiRef.current?.renderAll();
        },
        onUpdate(props) {
          setAnchor(props.clientRect?.() ?? null);
          rangeRef.current = props.range;
          if (props.query) apiRef.current?.renderFiltered(props.query);
          else apiRef.current?.renderAll();
        },
        onExit() {
          setOpen(false);
          rangeRef.current = null;
        },
        onKeyDown: ({ event }) => apiRef.current?.handleKey(event) ?? false,
      }),
      allow: ({ state, range }) => {
        const $from = state.doc.resolve(range.from);
        const type = state.schema.nodes[EmojiNode.name];
        return !!$from.parent.type.contentMatch.matchType(type);
      },
    });

    editor.registerPlugin(plugin, (p, plugins) => [p, ...plugins]);
    return () => {
      editor.unregisterPlugin(EmojiSuggestionPluginKey);
    };
  }, []);

  const virtualAnchor = useMemo(
    () => ({ getBoundingClientRect: () => anchor ?? new DOMRect() }),
    [anchor],
  );

  return (
    <Popover open={open} onOpenChange={() => setOpen(false)}>
      <PopoverContent
        initialFocus={false}
        finalFocus={false}
        anchor={virtualAnchor}
        sideOffset={24}
        side="right"
        align="center"
        className="w-lg h-120 p-0 flex flex-col gap-0 duration-200 ease-in overflow-visible shadow-2xl transition-all"
      >
        <PopoverTitle className="sr-only">Emoji Picker</PopoverTitle>
        <div ref={setContainer} />
        <PopoverArrow facing="left" align="center" size={18} />
      </PopoverContent>
    </Popover>
  );
});

// ─── ID convention (caller's responsibility) ───────────────────────────────
// Always pass `id` as UPPERCASE hex codepoints joined by "-":
//   single : "1F600"
//   multi  : "1F9D1-200D-1F91D-200D-1F9D1"
// Internal transforms (lowercase, underscore, etc.) are handled per-provider.
// ──────────────────────────────────────────────────────────────────────────

import type { GetEmojiUrl } from "../../config";

// ─── CDN bases ────────────────────────────────────────────────────────────
const CDN = {
  openmoji: "https://cdn.jsdelivr.net/gh/hfg-gmuend/openmoji@latest",
  twemoji: "https://cdn.jsdelivr.net/gh/jdecked/twemoji@latest/assets",
  noto: "https://raw.githubusercontent.com/googlefonts/noto-emoji/main",
  notoAnimated: "https://fonts.gstatic.com/s/e/notoemoji/latest",
  fluent: "https://cdn.jsdelivr.net/gh/UXDivers/emojis@main/fluent",
  emojitwo: "https://cdn.jsdelivr.net/npm/emojitwo/svg",
} as const;

export const getEmojiUrl: GetEmojiUrl = (hexId, source): string => {
  const lower = hexId.toLowerCase();
  const underscored = lower.replace(/-/g, "_");

  switch (source) {
    // Inline text — crisp at any scale, SVG beats a fixed-res PNG here
    case "inline":
      return `${CDN.twemoji}/svg/${lower}.svg`;

    // Picker grid — 72 px PNG is plenty for a small grid cell, lighter than SVG
    case "picker-grid":
      return `${CDN.twemoji}/72x72/${lower}.png`;

    // Category bar + callout icon — animated Noto, webp preferred
    case "category-bar":
    case "callout-icon":
      return `${CDN.notoAnimated}/${underscored}/512.webp`;
  }
};

import { getEmojiData } from "./data";
import { createCategoryBar } from "./category";
import { createEmojiGrid } from "./dom";
import { createNavigator } from "./navigation";
import { getFilteredEmojisByCategory } from "./utils";

const STORAGE_KEY = "recentEmojis";
const MAX_RECENT = 18;

export interface EmojiPickerOptions {
  onSelect: (shortcode: string) => void;
}

export type EmojiPickerApi = ReturnType<typeof createEmojiPicker>;

const createScaffold = () => {
  const scroll = document.createElement("div");
  scroll.className = "ep-scroll flex-1 overflow-auto min-h-0";
  scroll.style.scrollbarWidth = "none";
  (
    scroll.style as CSSStyleDeclaration & { msOverflowStyle?: string }
  ).msOverflowStyle = "none";

  const bar = document.createElement("div");
  bar.className =
    "ep-bar shrink-0 border-t transition-all duration-200 overflow-hidden flex justify-between px-2 py-1";

  return { scroll, bar };
};

export function createEmojiPicker(
  root: HTMLElement,
  options: EmojiPickerOptions,
) {
  const emojiData = getEmojiData();
  if (!emojiData) throw new Error("Emoji data not found");

  let recent: string[] =
    typeof localStorage !== "undefined"
      ? JSON.parse(localStorage.getItem(STORAGE_KEY) || "[]")
      : [];

  // Layout scaffold
  const { bar, scroll } = createScaffold();

  root.className = "h-full flex flex-col relative";
  root.appendChild(scroll);
  root.appendChild(bar);

  // Instantiate factories

  const area = createEmojiGrid(scroll);
  const nav = createNavigator(area.buttons, area.grids);
  const categoryBar = createCategoryBar(bar, scroll, (key) => {
    const gridIdx = area.getGridIdxForKey(key);
    nav.setFocusToGrid(gridIdx);
  });

  const selectById = (id: string) => {
    const shortcode = emojiData.emojis[id]?.shortcodes[0];
    if (!shortcode) return;
    recent = [id, ...recent.filter((x) => x !== id)].slice(0, MAX_RECENT);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(recent));
    options.onSelect(shortcode);
  };

  const selectFocused = () => {
    const idx = nav.getFocusedIdx();
    if (idx < 0) return;
    const img = area.buttons[idx].querySelector("img");
    if (img?.id) selectById(img.id);
  };

  const handleMouseMove = (e: MouseEvent) => {
    const btn = (e.target as HTMLElement).closest("button");
    if (!btn?.dataset.idx) return;
    nav.setFocus(parseInt(btn.dataset.idx));
  };

  const handlePointerDown = (e: PointerEvent) => {
    e.preventDefault();
    const target = e.target as HTMLElement;
    const img =
      target.tagName === "IMG"
        ? (target as HTMLImageElement)
        : (target.closest("button")?.querySelector("img") ?? null);
    if (img?.id && img.closest(".ep-scroll")) selectById(img.id);
  };

  scroll.addEventListener("mousemove", handleMouseMove, { passive: true });
  scroll.addEventListener("pointerdown", handlePointerDown);

  // Public render methods
  const renderAll = () => {
    area.clear();
    nav.reset();
    categoryBar.build(recent.length > 0);
    bar.style.display = "";

    if (recent.length > 0) area.addCategory("Recently Used", "recent", recent);

    emojiData.categories.forEach((category, i) => {
      area.timers.push(
        window.setTimeout(() => {
          area.addCategory(
            category.id.replace("-", " & "),
            category.id,
            category.emojis,
          );
        }, i * 500),
      );
    });
  };

  const renderFiltered = (query: string) => {
    area.clear();
    nav.reset();
    bar.style.display = "none";

    const groups = getFilteredEmojisByCategory(query);
    if (groups.length === 0) {
      area.showEmpty("No emojis found");
      return;
    }
    for (const { categoryId, ids } of groups) {
      area.addCategory(
        categoryId.replace("-", " & "),
        `search-${categoryId}`,
        ids,
      );
    }
  };

  const handleKey = (event: KeyboardEvent) =>
    nav.handleKey(event, selectFocused);

  const destroy = () => {
    area.destroy();
    scroll.removeEventListener("mousemove", handleMouseMove);
    scroll.removeEventListener("pointerdown", handlePointerDown);
    root.innerHTML = "";
  };

  return { renderAll, renderFiltered, handleKey, selectFocused, destroy };
}

import { getEditorConfig } from "@/components/editor/config";
import { getEmojiData } from "./data";

export const categoryId = (id: string) => `emoji-category-${id}`;
export function createCategoryBar(
  bar: HTMLDivElement,
  scroll: HTMLDivElement,
  onCategoryClick: (id: string) => void,
) {
  const build = (hasRecent: boolean) => {
    bar.innerHTML = "";

    const data = getEmojiData();
    if (!data) return;

    const entries: { id: string; icon: string }[] = [];
    if (hasRecent) entries.push({ id: "recent", icon: "231B" });
    for (const c of data.categories) entries.push({ id: c.id, icon: c.icon });

    for (const { id, icon } of entries) {
      const btn = document.createElement("button");
      btn.className =
        "inline-flex items-center justify-center rounded-md transition-colors hover:bg-gray-100 size-9";

      btn.onclick = () => {
        const target = document.getElementById(categoryId(id));

        if (!target) return;
        const delta =
          target.getBoundingClientRect().top -
          scroll.getBoundingClientRect().top -
          36;

        scroll.scrollTo({
          top: scroll.scrollTop + delta,
          behavior: "smooth",
        });

        onCategoryClick(id);
      };

      const img = document.createElement("img");
      img.src = getEditorConfig().getEmojiUrl(icon, "category-bar");
      img.className = "size-6 select-none";
      img.draggable = false;
      btn.appendChild(img);

      bar.appendChild(btn);
    }
  };

  return { build };
}

export interface EmojiSkin {
  unified: string;
  native: string;
  tone?: number | number[];
}

export interface Emoji {
  id: string;
  name: string;
  unicode: string;
  tags: string[];
  skins: EmojiSkin[];
  group: number;
  shortcodes: string[];
}

export interface EmojiCategory {
  id: string;
  icon: string;
  emojis: string[];
}

export interface EmojiData {
  emojis: Record<string, Emoji>;
  categories: EmojiCategory[];
}

// --- Singleton loader ---

let _cache: EmojiData | null = null;
let _emojiArray: Emoji[] | null = null;
let _inflight: Promise<EmojiData> | null = null;

/**
 * Configurable URL — point this to wherever emoji.json is served.
 * Defaults to /emoji.json (public folder in Next.js / Vite).
 */

export async function loadEmojiData(url: string): Promise<EmojiData> {
  if (_cache) return _cache;
  if (!_inflight) {
    _inflight = fetch(url)
      .then((r) => r.json())
      .then((data) => {
        _cache = data;
        _emojiArray = Object.values(data.emojis);
        return data;
      })
      .catch((err) => {
        _inflight = null;
        throw err;
      });
  }

  return _inflight;
}

/** Synchronous access — only valid after loadEmojiData() has resolved */
export function getEmojiData(): EmojiData | null {
  return _cache;
}

export function getEmojiArray(): Emoji[] {
  return _emojiArray ? _emojiArray : [];
}

import { getEmojiData } from "./data";
import { getEmojiUrl } from "../getEmojiUrl";
import { categoryId } from "./category";

export const COLUMN_COUNT = 10;

export function createEmojiGrid(scroll: HTMLDivElement) {
  const buttons: HTMLButtonElement[] = [];
  const grids: { start: number; count: number }[] = [];
  const categoryKeys: string[] = [];
  const timers: number[] = [];
  const headers: HTMLElement[] = [];

  const addHeader = (title: string) => {
    const header = document.createElement("div");
    header.className =
      "font-semibold text-sm text-gray-700 p-2 pb-1 pl-3.5 sticky top-0 bg-background z-10 capitalize";
    header.textContent = title;
    scroll.appendChild(header);
    headers.push(header);
  };

  const addGrid = (emojiIds: string[]) => {
    const data = getEmojiData();
    if (!data) return;

    const startIdx = buttons.length;
    const grid = document.createElement("div");
    grid.style.cssText = `display:grid;grid-template-columns:repeat(${COLUMN_COUNT},minmax(48px,1fr));padding:8px`;
    scroll.appendChild(grid);

    for (let i = 0; i < emojiIds.length; i++) {
      const emoji = data.emojis[emojiIds[i]];
      if (!emoji) continue;

      const button = document.createElement("button");
      button.className =
        "w-12 h-12 border-none rounded-md cursor-pointer flex items-center justify-center transition-colors duration-200 p-2 hover:bg-[#f3f4f6] text-2xl";

      const img = document.createElement("img");
      img.src = getEmojiUrl(emoji.id, "picker-grid");
      img.loading = "lazy";
      img.className = "block select-none";
      img.draggable = false;
      img.id = emoji.id;
      img.alt = emoji.unicode;
      img.title = emoji.name;
      img.onerror = () => {
        button.textContent = emoji.unicode;
        img.remove();
      };

      button.appendChild(img);
      grid.appendChild(button);
      button.dataset.idx = buttons.length.toString();
      buttons.push(button);
    }

    const count = buttons.length - startIdx;
    if (count > 0) grids.push({ start: startIdx, count });
  };

  const addCategory = (title: string, id: string, ids: string[]) => {
    addHeader(title);
    const beforeCount = buttons.length;
    const before = grids.length;
    addGrid(ids);
    const firstBtn = buttons[beforeCount];
    if (firstBtn) firstBtn.id = categoryId(id);
    if (grids.length > before) categoryKeys.push(id);
  };

  const getGridIdxForKey = (key: string) => categoryKeys.indexOf(key);

  const showEmpty = (message: string) => {
    const el = document.createElement("div");
    el.style.cssText =
      "text-align:center;padding:40px 20px;color:#6b7280;font-size:14px;";
    el.textContent = message;
    scroll.appendChild(el);
  };

  const clear = () => {
    timers.forEach(clearTimeout);
    timers.length = 0;
    scroll.innerHTML = "";
    buttons.length = 0;
    grids.length = 0;
    headers.length = 0;
  };

  return {
    buttons,
    grids,
    timers,
    addCategory,
    showEmpty,
    clear,
    getGridIdxForKey,
    destroy: () => {
      clear();
    },
  };
}

import { COLUMN_COUNT } from "./dom";

const FOCUSED_CLASS =
  "bg-accent outline outline-accent-foreground scroll-mt-10 scroll-mb-2.5".split(
    " ",
  );

const MOVES: Record<string, [number, number]> = {
  ArrowRight: [1, 0],
  ArrowLeft: [-1, 0],
  ArrowDown: [0, 1],
  ArrowUp: [0, -1],
};

export function createNavigator(
  buttons: HTMLButtonElement[],
  grids: { start: number; count: number }[],
) {
  let focusedIdx = -1;
  let desiredCol = 0;

  const gridOf = (idx: number) =>
    grids.findIndex((g) => idx >= g.start && idx < g.start + g.count);

  const lastRowStart = (count: number) =>
    Math.floor((count - 1) / COLUMN_COUNT) * COLUMN_COUNT;

  const landAt = (gi: number, rowStart: number, col: number) => {
    const g = grids[gi];
    const rowLen = Math.min(COLUMN_COUNT, g.count - rowStart);
    return g.start + rowStart + Math.min(col, rowLen - 1);
  };

  const focusAt = (next: number, scroll = true) => {
    if (!buttons.length) return;
    const clamped = Math.max(0, Math.min(next, buttons.length - 1));
    if (clamped === focusedIdx) return;
    if (focusedIdx >= 0) buttons[focusedIdx].classList.remove(...FOCUSED_CLASS);
    buttons[clamped].classList.add(...FOCUSED_CLASS);
    if (scroll) {
      buttons[clamped].scrollIntoView({ block: "nearest", behavior: "smooth" });
    }
    focusedIdx = clamped;
  };

  const setFocus = (next: number) => {
    focusAt(next);
    const gi = gridOf(focusedIdx);
    if (gi >= 0) desiredCol = (focusedIdx - grids[gi].start) % COLUMN_COUNT;
  };

  const move = (dx: number, dy: number) => {
    if (focusedIdx < 0) return setFocus(0);
    const gi = gridOf(focusedIdx);
    if (gi < 0) return;
    const g = grids[gi];
    const local = focusedIdx - g.start;
    const rowStart = local - (local % COLUMN_COUNT);

    if (dx) {
      const next = focusedIdx + dx;
      if (next >= g.start && next < g.start + g.count) {
        focusAt(next);
        desiredCol = (next - g.start) % COLUMN_COUNT;
      } else if (dx > 0 && gi + 1 < grids.length) {
        focusAt(grids[gi + 1].start);
        desiredCol = 0;
      } else if (dx < 0 && gi > 0) {
        const pg = grids[gi - 1];
        focusAt(pg.start + pg.count - 1);
        desiredCol = (pg.count - 1) % COLUMN_COUNT;
      }
      return;
    }

    const targetRow = rowStart + dy * COLUMN_COUNT;
    if (targetRow >= 0 && targetRow < g.count) {
      focusAt(landAt(gi, targetRow, desiredCol));
    } else if (dy > 0 && gi + 1 < grids.length) {
      focusAt(landAt(gi + 1, 0, desiredCol));
    } else if (dy < 0 && gi > 0) {
      focusAt(landAt(gi - 1, lastRowStart(grids[gi - 1].count), desiredCol));
    } else {
      setFocus(dy > 0 ? buttons.length - 1 : 0);
    }
  };

  const handleKey = (event: KeyboardEvent, onEnter: () => void): boolean => {
    if (!buttons.length) return false;
    if (event.key === "Enter") {
      event.preventDefault();
      onEnter();
      return true;
    }
    const delta = MOVES[event.key];
    if (!delta) return false;
    event.preventDefault();
    move(delta[0], delta[1]);
    return true;
  };

  const reset = () => {
    focusedIdx = -1;
    desiredCol = 0;
  };

  const setFocusToGrid = (gridIdx: number) => {
    if (gridIdx < 0 || gridIdx >= grids.length) return;
    focusAt(grids[gridIdx].start, false);
    desiredCol = 0;
  };

  const getFocusedIdx = () => focusedIdx;

  return { setFocus, move, handleKey, reset, getFocusedIdx, setFocusToGrid };
}

import { getEmojiData } from "./data";

export const getFilteredEmojisByCategory = (
  query: string,
): { categoryId: string; ids: string[] }[] => {
  const data = getEmojiData();
  if (!data) return [];
  const q = query.toLowerCase();
  const result: { categoryId: string; ids: string[] }[] = [];

  for (const category of data.categories) {
    const matches: string[] = [];
    for (const id of category.emojis) {
      const emoji = data.emojis[id];
      if (emoji?.name.toLowerCase().includes(q)) matches.push(id);
    }
    if (matches.length > 0) {
      result.push({ categoryId: category.id, ids: matches });
    }
  }
  return result;
};

import { Check } from "lucide-react";
import { DropdownMenuItem } from "@/components/editor/ui/dropdown-menu";
import { fontFamilies } from "./families";
import { AttributeHeader, AttributeMenu, getBlockAttr } from "../AttributeMenu";
import { cn } from "@/components/editor/lib/utils";
import { editorStore } from "../../store";

function applyFontFamily(family: string, pos?: number) {
  const { editor } = editorStore.get();
  if (!editor) return;

  const cmd = editor.chain().focus();
  if (pos !== undefined) {
    cmd.toggleBlockFontFamily(family, pos).run();
  } else {
    const active = getBlockAttr("fontFamily") === family;
    (active ? cmd.unsetFontFamily() : cmd.setFontFamily(family)).run();
  }
}

interface FontFamilyMenuProps {
  children: React.ReactNode;
  isSubMenu?: boolean | undefined;
  blockPos?: number | undefined;
}

export function FontFamilyMenu({
  children,
  isSubMenu,
  blockPos,
}: FontFamilyMenuProps) {
  const active = getBlockAttr("fontFamily", blockPos);

  return (
    <AttributeMenu trigger={children} isSub={isSubMenu}>
      <AttributeHeader title="Font family" />

      {fontFamilies.map((item) => {
        const isActive = item.value ? active === item.value : active === "";

        return (
          <DropdownMenuItem
            key={item.id}
            onClick={() => applyFontFamily(item.value, blockPos)}
            className={cn(
              "group flex items-center gap-3 px-2.5 py-2 rounded-md cursor-pointer",
              "focus:bg-accent/60 data-highlighted:bg-accent/60",
              isActive && "bg-accent/40",
            )}
          >
            <div
              className={cn(
                "flex h-9 w-9 shrink-0 items-center justify-center rounded-md",
                "bg-muted/60 border border-border/60",
                "text-[18px] leading-none font-medium",
                "transition-colors group-hover:bg-muted",
              )}
              style={{ fontFamily: item.value }}
              aria-hidden
            >
              Ag
            </div>

            <div className="flex min-w-0 flex-1 flex-col gap-0.5">
              <span
                className="text-[13px] leading-tight truncate"
                style={{ fontFamily: item.value }}
              >
                {item.label}
              </span>
            </div>

            {isActive && (
              <Check className="size-3.5 text-foreground shrink-0" />
            )}
          </DropdownMenuItem>
        );
      })}
    </AttributeMenu>
  );
}

