const ITEM = "flex items-center gap-2 h-8 px-2";

// ── Helpers ────────────────────────────────────────────────────────────

function act(fn: (ed: TypedEditor) => void, onClose: () => void) {
  const { editor } = editorStore.get();
  if (!editor) return;
  fn(editor);
  editor.commands.focus();
  onClose();
}

interface ItemDef {
  icon: LucideIcon;
  label: string;
  onClick: () => void;
  variant?: "destructive" | undefined;
}

function Items({ items }: { items: (ItemDef | "sep")[] }) {
  return items.map((item, i) =>
    item === "sep" ? (
      <DropdownMenuSeparator key={i} />
    ) : (
      <DropdownMenuItem
        key={i}
        variant={item.variant || "default"}
        className={ITEM}
        onClick={item.onClick}
      >
        <item.icon className="size-4" /> {item.label}
      </DropdownMenuItem>
    ),
  );
}

function ColorTrigger() {
  return (
    <div className={ITEM}>
      <Palette className="size-4" /> Color
    </div>
  );
}

