            icon: Eraser,
            label: "Clear row",
            onClick: () => clearRow(focused.tablePos, focused.rowIndex),
          },
          {
            icon: Trash2,
            label: "Delete row",
            variant: "destructive",
            onClick: () => a((ed) => chain(ed).deleteRow().run()),
          },
        ]}
      />
    </DropdownMenuContent>
  );
}

export function CellMenu({ focused, onClose }: MenuProps) {
  const a = (fn: (ed: TypedEditor) => void) => act(fn, onClose);

  return (
    <DropdownMenuContent
      side="right"
      align="center"
      sideOffset={4}
      className="w-[200px]"
    >
      <ColorMenu
        isSubMenu
        onSelectBg={(c) =>
          a((ed) =>
            ed
              .chain()
              .focus()
              .setTextSelection(focused.cellPosInDoc)
              .setCellAttribute("backgroundColor", c)
              .run(),
          )
        }
        onSelectText={(c) =>
          a((ed) => {
            const cellPos = focused.cellPosInDoc - 1;
            const cellNode = ed.state.doc.nodeAt(cellPos);
            if (!cellNode) return;
            const chain = ed
              .chain()
              .focus()
              .setTextSelection({
                from: focused.cellPosInDoc,
                to: cellPos + cellNode.nodeSize - 1,
              });
            c ? chain.setColor(c).run() : chain.unsetColor().run();
          })
        }
      >
        <ColorTrigger />
      </ColorMenu>
      <DropdownMenuSeparator />
      <Items
        items={[
          {
            icon: Eraser,
            label: "Clear cell",
            onClick: () =>
              clearCell(focused.tablePos, focused.rowIndex, focused.colIndex),
          },
        ]}
      />
    </DropdownMenuContent>
  );
}

import type { Node as PMNode } from "@tiptap/pm/model";
import { editorStore } from "../../store";

// ── DOM Helpers ────────────────────────────────────────────────────────

export function getColIndex(cellDom: HTMLElement): number {
  const row = cellDom.closest("tr");
  if (!row) return 0;
  return Array.from(row.children).indexOf(cellDom);
}

export function getRowIndex(cellDom: HTMLElement): number {
  const tbody = cellDom.closest("tbody, table");
  if (!tbody) return 0;
  const rows = Array.from(tbody.querySelectorAll(":scope > tr"));
  const row = cellDom.closest("tr");
  return row ? rows.indexOf(row) : 0;
}

// ── ProseMirror Position Helpers ───────────────────────────────────────

export function getTablePos(cellDomPos: number): number | null {
  try {
    const { editor } = editorStore.get();
    if (!editor) throw new Error("Editor not found");

    const $pos = editor.state.doc.resolve(cellDomPos);
    for (let d = $pos.depth; d >= 0; d--) {
      if ($pos.node(d).type.name === "table") return $pos.before(d);
    }
  } catch {
    // pos out of range
  }
  return null;
}

// ── Table Node Rebuild Helpers ─────────────────────────────────────────

function rebuildTable(
  tableNode: PMNode,
  mapRow: (cells: PMNode[], rowIdx: number) => PMNode[],
): PMNode {
  const newRows = tableNode.content.content.map((row, rowIdx) => {
    const cells = [...row.content.content];
    const newCells = mapRow(cells, rowIdx);
    return row.type.create(row.attrs, newCells, row.marks);
  });
  return tableNode.type.create(tableNode.attrs, newRows, tableNode.marks);
}

function applyTableReplace(tablePos: number, newTable: PMNode): void {
  const { editor } = editorStore.get();
  if (!editor) return;

  const { state, dispatch } = editor.view;
  const tableNode = state.doc.nodeAt(tablePos);
  if (!tableNode) return;
  dispatch(
    state.tr.replaceWith(tablePos, tablePos + tableNode.nodeSize, newTable),
  );
}

// ── Column Operations ──────────────────────────────────────────────────

export function moveColumn(tablePos: number, from: number, to: number): void {
  const { editor } = editorStore.get();
  if (from === to || !editor) return;
  const tableNode = editor.state.doc.nodeAt(tablePos);
  if (!tableNode) return;

  const newTable = rebuildTable(tableNode, (cells) => {
    const moved = [...cells];
    const [cell] = moved.splice(from, 1);
    moved.splice(to, 0, cell);
    return moved;
  });
  applyTableReplace(tablePos, newTable);
}

export function duplicateColumn(tablePos: number, colIdx: number): void {
  const { editor } = editorStore.get();
  const tableNode = editor?.state.doc.nodeAt(tablePos);
  if (!tableNode) return;

  const newTable = rebuildTable(tableNode, (cells) => {
    const result = [...cells];
    result.splice(colIdx + 1, 0, cells[colIdx]);
    return result;
  });
  applyTableReplace(tablePos, newTable);
}

function clearCells(
  tablePos: number,
  shouldClear: (rowIdx: number, colIdx: number) => boolean,
): void {
  const { editor } = editorStore.get();
  const tableNode = editor?.state.doc.nodeAt(tablePos);
  if (!tableNode) return;

  const emptyParagraph = editor!.state.schema.nodes.paragraph.create();
  const newTable = rebuildTable(tableNode, (cells, rowIdx) =>
    cells.map((cell, colIdx) =>
      shouldClear(rowIdx, colIdx)
        ? cell.type.create(cell.attrs, emptyParagraph, cell.marks)
        : cell,
    ),
  );
  applyTableReplace(tablePos, newTable);
}

export function clearColumn(tablePos: number, colIdx: number): void {
  clearCells(tablePos, (_, col) => col === colIdx);
}

// ── Row Operations ─────────────────────────────────────────────────────

export function moveRow(tablePos: number, from: number, to: number): void {
  const { editor } = editorStore.get();
  if (from === to || !editor) return;

  const tableNode = editor.state.doc.nodeAt(tablePos);
  if (!tableNode) return;

  const rows = [...tableNode.content.content];
  const [row] = rows.splice(from, 1);
  rows.splice(to, 0, row);

  const newTable = tableNode.type.create(
    tableNode.attrs,
    rows,
    tableNode.marks,
  );
  applyTableReplace(tablePos, newTable);
}

export function clearRow(tablePos: number, rowIdx: number): void {
  clearCells(tablePos, (row) => row === rowIdx);
}

// ── Background Color Operations ────────────────────────────────────────

function setCellBgs(
  tablePos: number,
  shouldColor: (rowIdx: number, colIdx: number) => boolean,
  color: string | null,
): void {
  const { editor } = editorStore.get();
  const tableNode = editor?.state.doc.nodeAt(tablePos);
  if (!tableNode) return;

  const tr = editor!.state.tr;
  let rowPos = tablePos + 1;
  let rowIdx = 0;
  tableNode.content.forEach((rowNode) => {
    let colIdx = 0;
    rowNode.content.forEach((cellNode, offset) => {
      if (shouldColor(rowIdx, colIdx)) {
        tr.setNodeMarkup(rowPos + 1 + offset, undefined, {
          ...cellNode.attrs,
          backgroundColor: color,
        });
      }
      colIdx++;
    });
    rowIdx++;
    rowPos += rowNode.nodeSize;
  });
  editor!.view.dispatch(tr);
}

export function setCellBgsForColumn(
  tablePos: number,
  colIdx: number,
  color: string | null,
): void {
  setCellBgs(tablePos, (_, col) => col === colIdx, color);
}

export function setCellBgsForRow(
  tablePos: number,
  rowIdx: number,
  color: string | null,
): void {
  setCellBgs(tablePos, (row) => row === rowIdx, color);
}

// ── Cell Operations ────────────────────────────────────────────────────

export function clearCell(
  tablePos: number,
  rowIdx: number,
  colIdx: number,
): void {
  clearCells(tablePos, (row, col) => row === rowIdx && col === colIdx);
}

import { useRef, useState, useCallback, useEffect } from "react";
import type { FocusedCell } from "./useTableFocus";
import { moveColumn, moveRow } from "./tableActions";
import { editorStore } from "../../store";

export interface DragState {
  axis: "col" | "row";
  fromIdx: number;
  toIdx: number;
  tablePos: number;
  tableDom: HTMLElement;
  startX: number;
  startY: number;
  isDragging: boolean;
}

const DRAG_THRESHOLD = 4;
const CELL_MIN_WIDTH = 75;

function getColMidpoints(tableDom: HTMLElement): number[] {
  const firstRow = tableDom.querySelector("tr");
  if (!firstRow) return [];
  return Array.from(firstRow.children).map((c) => {
    const r = (c as HTMLElement).getBoundingClientRect();
    return r.left + r.width / 2;
  });
}

function getRowMidpoints(tableDom: HTMLElement): number[] {
  return Array.from(tableDom.querySelectorAll(":scope > tr, tbody > tr")).map(
    (r) => {
      const rect = (r as HTMLElement).getBoundingClientRect();
      return rect.top + rect.height / 2;
    },
  );
}

function nearestIdx(mids: number[], v: number): number {
  return mids.reduce(
    (best, m, i) => (Math.abs(m - v) < Math.abs(mids[best] - v) ? i : best),
    0,
  );
}

function syncColWidths(tablePos: number) {
  const { editor } = editorStore.get();
  if (!editor) return;
  const table = editor.state.doc.nodeAt(tablePos);
  if (!table) return;
  const nodeDom = editor.view.nodeDOM(tablePos) as HTMLElement | null;
  if (!nodeDom) return;
  const tableEl =
    nodeDom.tagName === "TABLE"
      ? nodeDom
      : (nodeDom.querySelector("table") as HTMLElement | null);
  if (!tableEl) return;

  const firstRow = table.child(0);
  const widths: number[] = [];
  for (let i = 0; i < firstRow.childCount; i++) {
    widths.push(firstRow.child(i).attrs.colwidth?.[0] ?? 0);
  }

  const apply = (el: HTMLElement, w: number) => {
    if (w) {
      el.style.width = `${w}px`;
      el.style.minWidth = `${CELL_MIN_WIDTH}px`;
    } else {
      el.style.removeProperty("width");
      el.style.removeProperty("min-width");
    }
  };

  tableEl
    .querySelectorAll<HTMLElement>("col")
    .forEach((col, i) => apply(col, widths[i] ?? 0));

  Array.from(
    tableEl.querySelectorAll<HTMLTableRowElement>(":scope > tr, tbody > tr"),
  ).forEach((row) => {
    Array.from(row.children).forEach((cell, i) =>
      apply(cell as HTMLElement, widths[i] ?? 0),
    );
  });
}

export function useTableDrag() {
  const [drag, setDrag] = useState<DragState | null>(null);
  const dragRef = useRef<DragState | null>(null);
  const dragCleanupRef = useRef<(() => void) | null>(null);
  const didDragRef = useRef(false);

  useEffect(
    () => () => {
      dragRef.current = null;
      dragCleanupRef.current?.();
    },
    [],
  );

  const startDrag = useCallback(
    (
      e: React.MouseEvent,
      axis: "col" | "row",
      fromIdx: number,
      h: FocusedCell,
    ) => {
      e.preventDefault();
      e.stopPropagation();

      const state: DragState = {
        axis,
        fromIdx,
        toIdx: fromIdx,
        tablePos: h.tablePos,
        tableDom: h.tableWrapper,
        startX: e.clientX,
        startY: e.clientY,
        isDragging: false,
      };
      dragRef.current = state;

      const onMove = (ev: MouseEvent) => {
        const d = dragRef.current;
        if (!d) return;
        const delta =
          d.axis === "col" ? ev.clientX - d.startX : ev.clientY - d.startY;
        if (!d.isDragging && Math.abs(delta) < DRAG_THRESHOLD) return;
        const toIdx =
          d.axis === "col"
            ? nearestIdx(getColMidpoints(d.tableDom), ev.clientX)
            : nearestIdx(getRowMidpoints(d.tableDom), ev.clientY);
        dragRef.current = { ...d, isDragging: true, toIdx };
        setDrag({ ...d, isDragging: true, toIdx });
      };

      const onUp = () => {
        const d = dragRef.current;
        if (d?.isDragging) {
          didDragRef.current = true;
          requestAnimationFrame(() => {
            didDragRef.current = false;
          });
          if (d.axis === "col") {
            moveColumn(d.tablePos, d.fromIdx, d.toIdx);
            syncColWidths(d.tablePos);
          } else {
            moveRow(d.tablePos, d.fromIdx, d.toIdx);
          }
        }
        dragRef.current = null;
        dragCleanupRef.current = null;
        setDrag(null);
        window.removeEventListener("mousemove", onMove);
        window.removeEventListener("mouseup", onUp);
      };

      window.addEventListener("mousemove", onMove);
      window.addEventListener("mouseup", onUp);
      dragCleanupRef.current = () => {
        window.removeEventListener("mousemove", onMove);
        window.removeEventListener("mouseup", onUp);
      };
    },
    [],
  );

  return { drag, didDragRef, startDrag };
}

import { useState, useEffect } from "react";
import { getColIndex, getRowIndex, getTablePos } from "./tableActions";
import { cellAround } from "@tiptap/pm/tables";
import type { Node as PMNode } from "@tiptap/pm/model";
import { editorStore } from "../../store";
import type { TypedEditor } from "../../types";
import { BTN } from ".";

export interface FocusedCell {
  tableWrapper: HTMLElement;
  tablePos: number;
  cellPosInDoc: number;
  colIndex: number;
  rowIndex: number;
  col: { top: number; left: number; width: number };
  row: { top: number; left: number; height: number };
  cell: {
    top: number;
    left: number;
    height: number;
    width: number;
    trueLeft: number;
  };
}

function findTableAtSelection(editor: TypedEditor) {
  const { $anchor } = editor.state.selection;
  for (let depth = $anchor.depth; depth >= 0; depth--) {
    const node = $anchor.node(depth);
    if (node.type.name === "table") {
      const pos = depth === 0 ? 0 : $anchor.before(depth);
      const dom = editor.view.nodeDOM(pos) as HTMLElement | null;
      if (!dom) return null;
      return { node, pos, dom } as {
        node: PMNode;
        pos: number;
        dom: HTMLElement;
      };
    }
  }
  return null;
}

export function useTableFocus(): FocusedCell | null {
  const [focused, setFocused] = useState<FocusedCell | null>(null);

  useEffect(() => {
    const { editor } = editorStore.get();
    if (!editor) return;

    let observer: ResizeObserver | null = null;
    let observedCell: HTMLElement | null = null;
    let observedTable: HTMLElement | null = null;
    let rafId: number | null = null;

    const scheduleRemeasure = () => {
      if (rafId) return;
      rafId = requestAnimationFrame(() => {
        rafId = null;
        measure();
      });
    };

    const ensureObserving = (cellDom: HTMLElement, tableDom: HTMLElement) => {
      if (observedCell === cellDom && observedTable === tableDom) return;
      observer?.disconnect();
      observer = new ResizeObserver(scheduleRemeasure);
      observer.observe(cellDom);
      observer.observe(tableDom);
      observedCell = cellDom;
      observedTable = tableDom;
    };

    const teardown = () => {
      observer?.disconnect();
      observer = null;
      observedCell = null;
      observedTable = null;
      if (rafId) cancelAnimationFrame(rafId);
      rafId = null;
    };

    const measure = () => {
      const table = findTableAtSelection(editor);
      if (!table) {
        teardown();
        return setFocused(null);
      }

      const cellPos = cellAround(editor.state.selection.$anchor)?.pos;
      if (cellPos == null) return setFocused(null);

      const cellDom = editor.view.nodeDOM(cellPos) as HTMLElement | null;
      if (!cellDom) return setFocused(null);

      const wrapperDom = table.dom;
      const tableDom = wrapperDom.querySelector(
        "table",
      ) as HTMLTableElement | null;
      if (!tableDom) return setFocused(null);

      ensureObserving(cellDom, tableDom);

      const tablePos = getTablePos(cellPos + 1);
      if (tablePos === null) return setFocused(null);

      setFocused({
        tableWrapper: wrapperDom,
        tablePos,
        cellPosInDoc: cellPos + 1,
        colIndex: getColIndex(cellDom),
        rowIndex: getRowIndex(cellDom),
        col: {
          top: tableDom.offsetTop - BTN,
          left: cellDom.offsetLeft,
          width: cellDom.offsetWidth,
        },
        row: {
          top: cellDom.offsetTop,
          left: tableDom.offsetLeft - BTN,
          height: cellDom.offsetHeight,
        },
        cell: {
          top: cellDom.offsetTop,
          left: cellDom.offsetLeft + cellDom.offsetWidth - BTN / 2,
          height: cellDom.offsetHeight,
          width: cellDom.offsetWidth,
          trueLeft: cellDom.offsetLeft,
        },
      });
    };

    measure();
    editor.on("selectionUpdate", measure);
    editor.on("focus", measure);
    return () => {
      editor.off("selectionUpdate", measure);
      editor.off("focus", measure);
      teardown();
    };
  }, []);

  return focused;
}

import {
  Type,
  Heading1,
  Heading2,
  Heading3,
  List,
  ListOrdered,
  ListChecks,
  Quote,
