  flex: 1 1 auto;
}

/* ── Blockquote ────────────────────────────────────────────────────── */

.ProseMirror blockquote {
  border-left: 3px solid var(--editor-border);
  padding-left: 1rem;
  color: var(--editor-text-secondary);
}

/* ── Code ──────────────────────────────────────────────────────────── */

/* Pre inside custom CodeBlock NodeView — wrapper handles bg/radius */
.ProseMirror pre {
  font-family: var(--font-mono);
  font-size: 14px;
  background: transparent;
  padding: 0;
  margin: 0;
  border-radius: 0;
}

/* Inline code only (not inside code blocks) */
.ProseMirror :not(pre) > code {
  color: var(--editor-accent);
  background: var(--editor-surface);
  padding: 0.2em 0.4em;
  border-radius: 0.25em;
  font-family: var(--font-mono);
  font-size: 0.9em;
}

/* ── Horizontal Rule ───────────────────────────────────────────────── */

.tiptap hr {
  height: 1.5em; /* big hit + hover area */
  border: none;
  background: linear-gradient(
    transparent calc(50% - 0.5px),
    #ccc calc(50% - 0.5px),
    #ccc calc(50% + 0.5px),
    transparent calc(50% + 0.5px)
  );
  margin: 0;
  cursor: default;
}

/* ── Links ─────────────────────────────────────────────────────────── */

.ProseMirror a.editor-link {
  color: var(--editor-accent);
  text-decoration: underline;
  text-underline-offset: 2px;
  cursor: pointer;
  transition: opacity 0.15s ease;
}

.ProseMirror a.editor-link:hover {
  opacity: 0.8;
}

/* ── Callout ──────────────────────────────────────────────────────── */

.ProseMirror div[data-type="callout"] p.is-empty::before {
  content: attr(data-placeholder);
  float: left;
  color: var(--editor-text-muted);
  pointer-events: none;
  height: 0;
}

/* ── Table ─────────────────────────────────────────────────────────── */

.ProseMirror .tableWrapper {
  position: relative;
  margin-top: 1.2em;
  margin-bottom: 2em;
}

.ProseMirror .table-container {
  overflow-x: auto;
  overflow-y: hidden;
  scrollbar-width: none;
  position: relative;
  padding: 6px 6px 2px 6px; /* top right bottom left */
}

.ProseMirror table {
  border-collapse: collapse;
  table-layout: fixed;
  width: 100%;
  margin: 0;
  overflow: hidden;
}

.ProseMirror table td,
.ProseMirror table th {
  border: 1px solid var(--editor-border);
  padding: 0.5rem 0.75rem;
  vertical-align: top;
  position: relative;
  box-sizing: border-box;
}

.ProseMirror table th {
  background: var(--editor-surface);
  font-weight: 600;
  text-align: left;
}

/* prosemirror-tables adds .selectedCell on the active cell */
.ProseMirror table .selectedCell::after {
  content: "";
  position: absolute;
  inset: 0;
  background: var(--editor-selected);
  pointer-events: none;
  z-index: 2;
}

.ProseMirror table .column-resize-handle {
  position: absolute;
  right: -2px;
  top: 0;
  bottom: 0;
  width: 2px;
  background-color: var(--editor-accent);
  pointer-events: none;
  z-index: 20;
}

.ProseMirror.resize-cursor {
  cursor: col-resize;
}

/* Block Context Menu Webkit Scrollbar */

.block-context-menu::-webkit-scrollbar {
  width: 4px;
}

.block-context-menu::-webkit-scrollbar-track {
  background: transparent;
}

.block-context-menu::-webkit-scrollbar-thumb {
  background-color: #3f3f46;
  border-radius: 4px;
}

/* callout.css */
.callout {
  display: flex;
  align-items: flex-start;
  gap: 8px;
  padding: 12px 16px;
  margin: 0.5em 0;
  border-radius: 8px;
  background-color: var(--color-accent);
  border: 1px solid var(--color-border);
}

.callout-emoji {
  flex-shrink: 0;
  width: 28px;
  height: 28px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 18px;
  line-height: 1;
  border-radius: 4px;
  cursor: pointer;
  user-select: none;
  border: none;
  background: transparent;
  transition: background-color 150ms;
}
.callout-emoji:hover {
  background-color: var(--color-muted);
}

.callout-content {
  flex: 1;
  min-width: 0;
}
.callout-content > *:first-child {
  margin-top: 0;
}
.callout-content > *:last-child {
  margin-bottom: 0;
}
